// MHPCO Claim Office implementation

export type ItemType = 'sword' | 'amulet' | 'staff' | 'potion' | 'rune' | 'moonstone';

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface Customer {
  yearsWithMHPCO: number;
}

export interface QuoteStep {
  op: 'quote';
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: 'claim';
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface Output {
  results: StepResult[];
}

const MAIN_ITEMS: Record<string, { value: number; basePremium: number }> = {
  sword: { value: 1000, basePremium: 100 },
  amulet: { value: 600, basePremium: 60 },
  staff: { value: 800, basePremium: 80 },
  potion: { value: 400, basePremium: 40 },
};

const COMPONENT_TYPES = new Set(['rune', 'moonstone']);
const COMPONENT_VALUE = 250;
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const DEDUCTIBLE = 100;
const PROCESSING_FEE = 5;

const CURSE_SURCHARGE = 0.5;
const HIGH_ENCH_SURCHARGE = 0.3;
const HIGH_ENCH_THRESHOLD = 5;
const LOYALTY_DISCOUNT = 0.2;
const LOYALTY_YEARS = 2;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;

const DAMAGE_HALF_ENCH_THRESHOLD = 8;
const DRAGON_MATERIAL = 'dragon';

interface Policy {
  items: Item[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
}

function isKnownType(type: string): boolean {
  return type in MAIN_ITEMS || COMPONENT_TYPES.has(type);
}

function itemInsuranceValue(item: Item): number {
  if (item.type in MAIN_ITEMS) {
    return MAIN_ITEMS[item.type].value;
  }
  if (COMPONENT_TYPES.has(item.type)) {
    return COMPONENT_VALUE;
  }
  throw new Error(`Unknown item type: ${item.type}`);
}

function itemBasePremium(item: Item): number {
  if (item.type in MAIN_ITEMS) {
    return MAIN_ITEMS[item.type].basePremium;
  }
  if (COMPONENT_TYPES.has(item.type)) {
    return COMPONENT_BASE_PREMIUM;
  }
  throw new Error(`Unknown item type: ${item.type}`);
}

function computeComponentBasePremium(components: Item[]): number {
  // Group by type, apply block discount per group
  const byType = new Map<string, number>();
  for (const c of components) {
    byType.set(c.type, (byType.get(c.type) ?? 0) + 1);
  }
  let total = 0;
  for (const [, count] of byType) {
    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
    const remainder = count % COMPONENT_BLOCK_SIZE;
    total += blocks * COMPONENT_BLOCK_PREMIUM + remainder * COMPONENT_BASE_PREMIUM;
  }
  return total;
}

function itemBasePremiumWithModifiers(item: Item): number {
  let base = itemBasePremium(item);
  let surcharge = 0;
  if (item.cursed) {
    surcharge += base * CURSE_SURCHARGE;
  }
  if (typeof item.enchantment === 'number' && item.enchantment >= HIGH_ENCH_THRESHOLD) {
    surcharge += base * HIGH_ENCH_SURCHARGE;
  }
  return base + surcharge;
}

function roundUp(n: number): number {
  return Math.ceil(n - 1e-9);
}

function roundDown(n: number): number {
  return Math.floor(n + 1e-9);
}

export function computePremium(items: Item[], customer: Customer, quoteIndex: number): number {
  // Validate item types first
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  // Compute item-level (cursed/high-ench applied per item)
  const mainItems = items.filter((i) => i.type in MAIN_ITEMS);
  const components = items.filter((i) => COMPONENT_TYPES.has(i.type));

  let itemsTotal = 0;
  for (const item of mainItems) {
    itemsTotal += itemBasePremiumWithModifiers(item);
  }
  // Components: compute block base premium ignoring per-item enchantment/curse,
  // then add per-component surcharges (cursed components — spec doesn't mention,
  // but treat consistently)
  // Spec only mentions cursed/high-enchantment for main items typically; runes have
  // no enchantment level per the standard reimbursement example, so just compute base.
  itemsTotal += computeComponentBasePremium(components);
  // Add per-component cursed/enchantment surcharges if any
  for (const c of components) {
    let extra = 0;
    if (c.cursed) {
      extra += COMPONENT_BASE_PREMIUM * CURSE_SURCHARGE;
    }
    if (typeof c.enchantment === 'number' && c.enchantment >= HIGH_ENCH_THRESHOLD) {
      extra += COMPONENT_BASE_PREMIUM * HIGH_ENCH_SURCHARGE;
    }
    itemsTotal += extra;
  }

  // Policy-wide modifiers on policy base premium (sum of item base premiums incl. item modifiers)
  let policyTotal = itemsTotal;
  // Loyalty discount
  if (customer.yearsWithMHPCO >= LOYALTY_YEARS) {
    policyTotal -= itemsTotal * LOYALTY_DISCOUNT;
  }
  // First insurance surcharge: applies to each item base premium (per spec note)
  // "each item in a quote is treated as a first insurance" — so 10% of sum of item base premiums
  const sumOfItemBasePremiums = items.reduce((acc, i) => {
    if (i.type in MAIN_ITEMS) return acc + MAIN_ITEMS[i.type].basePremium;
    return acc + COMPONENT_BASE_PREMIUM;
  }, 0);
  policyTotal += sumOfItemBasePremiums * FIRST_INSURANCE_SURCHARGE;

  // Follow-up contract discount applies on quotes after the first
  if (quoteIndex > 0) {
    policyTotal -= itemsTotal * FOLLOWUP_CONTRACT_DISCOUNT;
  }

  // Processing fee at the very end
  const final = policyTotal + PROCESSING_FEE;
  return roundUp(final);
}

export function computeInsuranceSum(items: Item[]): number {
  return items.reduce((acc, i) => acc + itemInsuranceValue(i), 0);
}

function matchItemForDamage(policy: Policy, itemType: string, usedIndices: Set<number>): Item {
  for (let i = 0; i < policy.items.length; i++) {
    if (usedIndices.has(i)) continue;
    if (policy.items[i].type === itemType) {
      usedIndices.add(i);
      return policy.items[i];
    }
  }
  throw new Error(`Damage references item type "${itemType}" not in policy or already accounted for`);
}

function damagePayout(item: Item, damageAmount: number): number {
  const isDragon = item.material === DRAGON_MATERIAL;
  const isHighEnch = typeof item.enchantment === 'number' && item.enchantment >= DAMAGE_HALF_ENCH_THRESHOLD;
  let reimbursed: number;
  if (isDragon) {
    // dragon material → full reimbursement (overrides high-enchantment? per spec:
    // "dragon-material sword, enchantment 9, damage 1000 → payout 400 (both clauses apply; 50% rule wins, then deductible)")
    // So when both apply, 50% wins.
    if (isHighEnch) {
      reimbursed = damageAmount * 0.5;
    } else {
      reimbursed = damageAmount;
    }
  } else if (isHighEnch) {
    reimbursed = damageAmount * 0.5;
  } else {
    reimbursed = damageAmount;
  }
  const afterDeductible = reimbursed - DEDUCTIBLE;
  return Math.max(0, afterDeductible);
}

export function processClaim(policy: Policy, incident: Incident): ClaimResult {
  // Validate damage amounts
  for (const d of incident.damages) {
    if (d.amount < 0) {
      throw new Error(`Negative damage amount: ${d.amount}`);
    }
    if (!isKnownType(d.itemType)) {
      throw new Error(`Unknown damage item type: ${d.itemType}`);
    }
  }

  // Match each damage to a distinct policy item; if not possible, reject.
  const usedIndices = new Set<number>();
  const matched: { item: Item; damage: Damage }[] = [];
  for (const d of incident.damages) {
    const item = matchItemForDamage(policy, d.itemType, usedIndices);
    matched.push({ item, damage: d });
  }

  // Compute total raw payout (before cap)
  let totalPayout = 0;
  for (const { item, damage } of matched) {
    totalPayout += damagePayout(item, damage.amount);
  }

  // Apply cap (uses remainingCap)
  const payoutBeforeRound = Math.min(totalPayout, policy.remainingCap);
  const payout = roundDown(payoutBeforeRound);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
}

export function runScenario(scenario: Scenario): Output {
  const results: StepResult[] = [];
  const policies = new Map<number, Policy>();
  let quoteCount = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === 'quote') {
      const premium = computePremium(step.items, scenario.customer, quoteCount);
      const insuranceSum = computeInsuranceSum(step.items);
      const cap = insuranceSum * 2;
      policies.set(i, {
        items: step.items,
        insuranceSum,
        cap,
        remainingCap: cap,
      });
      results.push({ premium });
      quoteCount++;
    } else if (step.op === 'claim') {
      const policy = policies.get(step.policy);
      if (!policy) {
        throw new Error(`Claim references unknown policy index: ${step.policy}`);
      }
      const claimResult = processClaim(policy, step.incident);
      results.push(claimResult);
    } else {
      throw new Error(`Unknown op: ${(step as { op: string }).op}`);
    }
  }

  return { results };
}

