  // Match each damage to a distinct policy item; if not possible, reject.
  const usedIndices = new Set<number>();
  const matched: { item: Item; damage: Damage }[] = [];
  for (const d of incident.damages) {
    const item = matchItemForDamage(policy, d.itemType, usedIndices);
    matched.push({ item, damage: d });
  }

  // Compute total raw payout (before cap)
  let totalPayout = 0;
  for (const { item, damage } of matched) {
    totalPayout += damagePayout(item, damage.amount);
  }

  // Apply cap (uses remainingCap)
  const payoutBeforeRound = Math.min(totalPayout, policy.remainingCap);
  const payout = roundDown(payoutBeforeRound);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
}

export function runScenario(scenario: Scenario): Output {
  const results: StepResult[] = [];
  const policies = new Map<number, Policy>();
  let quoteCount = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === 'quote') {
      const premium = computePremium(step.items, scenario.customer, quoteCount);
      const insuranceSum = computeInsuranceSum(step.items);
      const cap = insuranceSum * 2;
      policies.set(i, {
        items: step.items,
        insuranceSum,
        cap,
        remainingCap: cap,
      });
      results.push({ premium });
      quoteCount++;
    } else if (step.op === 'claim') {
      const policy = policies.get(step.policy);
      if (!policy) {
        throw new Error(`Claim references unknown policy index: ${step.policy}`);
      }
      const claimResult = processClaim(policy, step.incident);
      results.push(claimResult);
    } else {
      throw new Error(`Unknown op: ${(step as { op: string }).op}`);
    }
  }

  return { results };
}

