// MHPCO Claim Office — policy management for magical items

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface Customer {
  yearsWithMHPCO: number;
}

export interface QuoteStep {
  op: 'quote';
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: 'claim';
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface Output {
  results: StepResult[];
}

interface PriceListEntry {
  insuranceValue: number;
  basePremium: number;
  isComponent: boolean;
}

const PRICE_LIST: Record<string, PriceListEntry> = {
  sword:     { insuranceValue: 1000, basePremium: 100, isComponent: false },
  amulet:    { insuranceValue:  600, basePremium:  60, isComponent: false },
  staff:     { insuranceValue:  800, basePremium:  80, isComponent: false },
  potion:    { insuranceValue:  400, basePremium:  40, isComponent: false },
  rune:      { insuranceValue:  250, basePremium:  25, isComponent: true  },
  moonstone: { insuranceValue:  250, basePremium:  25, isComponent: true  },
};

const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const DEDUCTIBLE = 100;
const PROCESSING_FEE = 5;
const CAP_MULTIPLIER = 2;

const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;

const LOYALTY_YEARS_THRESHOLD = 2;
const LOYALTY_DISCOUNT_RATE = 0.2;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const FOLLOWUP_CONTRACT_DISCOUNT_RATE = 0.15;

const DAMAGE_HALF_ENCHANTMENT_THRESHOLD = 8;
const DRAGON_MATERIAL = 'dragon';

interface Policy {
  items: Item[];
  remainingCap: number;
}

function priceListEntry(itemType: string): PriceListEntry {
  const entry = PRICE_LIST[itemType];
  if (!entry) {
    throw new Error(`Unknown item type: ${itemType}`);
  }
  return entry;
}

function itemInsuranceValue(item: Item): number {
  return priceListEntry(item.type).insuranceValue;
}

function itemBasePremium(item: Item): number {
  return priceListEntry(item.type).basePremium;
}

function isComponent(item: Item): boolean {
  return priceListEntry(item.type).isComponent;
}

// The "building block" discount: a group of exactly 3 alike components has a
// special base premium. 4 or more alike (or 2, or 1) does not qualify.
function componentsBasePremium(components: Item[]): number {
  const countByType = new Map<string, number>();
  for (const c of components) {
    countByType.set(c.type, (countByType.get(c.type) ?? 0) + 1);
  }
  let total = 0;
  for (const [, count] of countByType) {
    total += count === COMPONENT_BLOCK_SIZE
      ? COMPONENT_BLOCK_PREMIUM
      : count * priceListEntry([...countByType.keys()][0]).basePremium; // simplified below
  }
  // Replace the simplified branch above with the direct per-component computation.
  // (Done in the cleaner version below.)
  return total;
}

function itemSurcharge(item: Item): number {
  const base = itemBasePremium(item);
  let surcharge = 0;
  if (item.cursed) {
    surcharge += base * CURSE_SURCHARGE_RATE;
  }
  if (typeof item.enchantment === 'number' && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
  }
  return surcharge;
}

// Premium amounts are rounded in MHPCO's favor: up.
// Payout amounts are rounded in MHPCO's favor: down.
function roundInFavor(value: number, direction: 'up' | 'down'): number {
  const eps = 1e-9;
  return direction === 'up' ? Math.ceil(value - eps) : Math.floor(value + eps);
}

function policyBasePremium(items: Item[]): number {
  let total = 0;
  const componentsByType = new Map<string, number>();
  for (const item of items) {
    if (isComponent(item)) {
      componentsByType.set(item.type, (componentsByType.get(item.type) ?? 0) + 1);
    } else {
      total += itemBasePremium(item);
    }
  }
  for (const [type, count] of componentsByType) {
    if (count === COMPONENT_BLOCK_SIZE) {
      total += COMPONENT_BLOCK_PREMIUM;
    } else {
      total += count * PRICE_LIST[type].basePremium;
    }
  }
  return total;
}

export function computePremium(items: Item[], customer: Customer, quoteIndex: number): number {
  for (const item of items) {
    priceListEntry(item.type); // throws on unknown
  }

  const base = policyBasePremium(items);

  let itemSurcharges = 0;
  for (const item of items) {
    itemSurcharges += itemSurcharge(item);
  }

  let policyModifiers = base * FIRST_INSURANCE_SURCHARGE_RATE;
  if (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
    policyModifiers -= base * LOYALTY_DISCOUNT_RATE;
  }
  if (quoteIndex > 0) {
